import { defineConfig } from '@docmd/core';

export default defineConfig({
  layout: {
    optionsMenu: {
      position: 'header', // 'header', 'sidebar-top', 'sidebar-bottom', or 'menubar'
      components: {
        search: true // Set to false to disable the search plugin entirely
      }
    }
  }
});
```

